using Ledgerly.Application.Abstractions; using Ledgerly.Domain.Entities; using Microsoft.EntityFrameworkCore; namespace Ledgerly.Infrastructure.Persistence.Repositories; public sealed class InvoiceRepository:IInvoiceRepository{ private readonly LedgerlyDbContext _context; public InvoiceRepository(LedgerlyDbContext context)=>_context=context; public Task<Invoice?> GetByIdAsync(Guid organizationId,Guid invoiceId,CancellationToken cancellationToken=default)=>_context.Invoices.Include(i=>i.Lines).FirstOrDefaultAsync(i=>i.OrganizationId==organizationId&&i.Id==invoiceId,cancellationToken); public async Task<IReadOnlyList<Invoice>> ListByOrganizationAsync(Guid organizationId,CancellationToken cancellationToken=default)=>await _context.Invoices.Include(i=>i.Lines).Where(i=>i.OrganizationId==organizationId).OrderByDescending(i=>i.IssueDate).ToListAsync(cancellationToken); public async Task AddAsync(Invoice invoice,CancellationToken cancellationToken=default){await _context.Invoices.AddAsync(invoice,cancellationToken);await _context.SaveChangesAsync(cancellationToken);} public async Task UpdateAsync(Invoice invoice,CancellationToken cancellationToken=default){_context.Invoices.Update(invoice);await _context.SaveChangesAsync(cancellationToken);} } public sealed class TaxCodeRepository:ITaxCodeRepository{ private readonly LedgerlyDbContext _context; public TaxCodeRepository(LedgerlyDbContext context)=>_context=context; public Task<TaxCode?> GetByIdAsync(Guid organizationId,Guid taxCodeId,CancellationToken cancellationToken=default)=>_context.TaxCodes.FirstOrDefaultAsync(t=>t.OrganizationId==organizationId&&t.Id==taxCodeId,cancellationToken); public async Task AddAsync(TaxCode taxCode,CancellationToken cancellationToken=default){await _context.TaxCodes.AddAsync(taxCode,cancellationToken);await _context.SaveChangesAsync(cancellationToken);} }
